const budget = 272500;
const records = {R1:{m1:96,m2:0,m3:55,m4:896},R2:{m1:493,m2:1,m3:638,m4:666},R3:{m1:767,m2:0,m3:534,m4:29},R4:{m1:627,m2:0,m3:811,m4:530}};
const rows = Object.entries(records).map(([id,r]) => ({id,priority:r.m1*r.m2-0.6*r.m3+r.m4,priority5:(r.m1*1.05)*r.m2-0.6*(r.m3*1.05)+(r.m4*1.05)})).sort((a,b)=>b.priority-a.priority);
const posSum = rows.reduce((a,r)=>a+Math.max(r.priority,0),0);
for (const r of rows) console.log(r.id, (budget*Math.max(r.priority,0)/posSum).toFixed(2), r.priority5.toFixed(2));
